/* 1. Reading progress bar */
(function(){var a=document.querySelector("article"),p=a&&a.querySelector(".prose");if(!a||!p)return;var b=document.createElement("div");b.id="reading-progress";document.body.appendChild(b);window.addEventListener("scroll",function(){var r=a.getBoundingClientRect(),t=a.offsetHeight-window.innerHeight;if(t>0)b.style.width=Math.min(Math.max(-r.top/t,0),1)*100+"%"},{passive:true})})();
/* 2. ToC scroll-spy */
(function(){var tl=document.querySelectorAll('aside nav ul li a[href^="#"]');if(!tl.length)return;var ids=[];tl.forEach(function(a){ids.push(a.getAttribute("href").slice(1))});var h=ids.map(function(id){return document.getElementById(id)}).filter(Boolean);if(!h.length)return;var o=new IntersectionObserver(function(entries){entries.forEach(function(e){var l=document.querySelector('aside nav ul li a[href="#'+e.target.id+'"]');if(l&&e.isIntersecting){tl.forEach(function(a){a.classList.remove("toc-active")});l.classList.add("toc-active")}})},{rootMargin:"-80px 0px -70% 0px",threshold:0});h.forEach(function(el){o.observe(el)})})();
/* 3. Mobile menu toggle + Escape key */
(function(){var t=document.getElementById("menu-toggle");if(!t)return;var m=document.getElementById("mobile-menu"),o=document.querySelector(".menu-open"),c=document.querySelector(".menu-close");t.addEventListener("click",function(){var h=m.classList.contains("hidden");m.classList.toggle("hidden");o.classList.toggle("hidden",h);c.classList.toggle("hidden",!h);t.setAttribute("aria-expanded",String(h))});document.addEventListener("keydown",function(e){if(e.key==="Escape"&&m&&!m.classList.contains("hidden")){m.classList.add("hidden");o.classList.remove("hidden");c.classList.add("hidden");t.setAttribute("aria-expanded","false");t.focus()}})})();
/* 4. Language switcher dropdown */
(function(){function init(v){var sfx=v?"-"+v:"",s=document.getElementById("lang-switcher"+sfx);if(!s)return;var b=document.getElementById("lang-toggle"+sfx),m=document.getElementById("lang-menu"+sfx);b.addEventListener("click",function(e){e.stopPropagation();var h=m.classList.contains("is-hidden");m.classList.toggle("is-hidden");b.setAttribute("aria-expanded",String(h))});document.addEventListener("click",function(e){if(!s.contains(e.target)){m.classList.add("is-hidden");b.setAttribute("aria-expanded","false")}});document.addEventListener("keydown",function(e){if(e.key==="Escape"&&!m.classList.contains("is-hidden")){m.classList.add("is-hidden");b.setAttribute("aria-expanded","false");b.focus()}})}init("desktop");init("mobile")})();
/* 5. Code copy buttons */
(function(){var c=document.getElementById("sayfa-code-copy");if(!c)return;var sel=c.getAttribute("data-selector")||"pre code",ct=c.getAttribute("data-copy-text")||"Copy",cd=c.getAttribute("data-copied-text")||"Copied!";document.querySelectorAll(sel).forEach(function(block){var pre=block.parentNode;if(pre.parentNode.classList.contains("code-block-wrap"))return;var lang=block.className.replace(/^language-/,"")||"";var w=document.createElement("div");w.className="code-block-wrap not-prose";var h=document.createElement("div");h.className="code-block-header";h.innerHTML='<span class="code-block-lang">'+lang+'</span><button class="copy-btn code-copy-btn"><svg class="code-copy-icon icon-copy" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24" aria-hidden="true"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg><svg class="code-copy-icon code-copy-icon-check icon-check" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24" aria-hidden="true"><path d="M20 6 9 17l-5-5"/></svg><span class="copy-label">'+ct+"</span></button>";var btn=h.querySelector(".copy-btn");btn.addEventListener("click",function(){var code=btn.closest(".code-block-wrap").querySelector("code").textContent;navigator.clipboard.writeText(code).then(function(){btn.classList.add("copied");btn.querySelector(".copy-label").textContent=cd;setTimeout(function(){btn.classList.remove("copied");btn.querySelector(".copy-label").textContent=ct},2000)}).catch(function(){})});pre.style.margin="0";pre.className="code-block-pre";var p=pre.parentNode;p.insertBefore(w,pre);w.appendChild(h);w.appendChild(pre)})})();
/* 6. Copy link buttons */
(function(){document.addEventListener("click",function(e){var b=e.target.closest('[data-action="copy-link"]');if(!b)return;var s=b.querySelector("span"),ct=b.getAttribute("data-copy-text"),cd=b.getAttribute("data-copied-text");navigator.clipboard.writeText(window.location.href).then(function(){s.textContent=cd;setTimeout(function(){s.textContent=ct},2000)}).catch(function(){})})})();
